function setFilterOptions(selector,label,values){const element=$(selector),selected=element.value;element.innerHTML=`<option value="">${label}</option>`+values.filter(Boolean).sort((a,b)=>a.localeCompare(b,"pt-BR")).map(value=>`<option>${value}</option>`).join("");element.value=selected}
function renderIssues(){setFilterOptions("#statusFilter","Todos os status",[...new Set(state.issues.map(i=>i.status))]);setFilterOptions("#typeFilter","Todos os tipos",[...new Set(state.issues.map(i=>i.type))]);setFilterOptions("#companyFilter","Todas as empresas",[...new Set(state.issues.map(i=>i.company))]);setFilterOptions("#assetFilter","Todos os ativos",[...new Set(state.issues.map(i=>i.asset))]);setFilterOptions("#classificationFilter","Todas as classificações",[...new Set(state.issues.map(i=>i.classification))]);setFilterOptions("#ownerFilter","Todos os responsáveis FICO",[...new Set(state.issues.map(i=>i.owner).filter(i=>i!=="Não atribuído"))]);filterIssues()}
function activeFilters(){return {q:$("#issueSearch").value.trim(),status:$("#statusFilter").value,specialty:$("#typeFilter").value,company:$("#companyFilter").value,asset:$("#assetFilter").value,classification:$("#classificationFilter").value,fico_owner:$("#ownerFilter").value,opened_from:$("#openedFromFilter").value,opened_to:$("#openedToFilter").value}}
function reportQuery(ignoreCompany=false){const params=new URLSearchParams();for(const [key,value] of Object.entries(activeFilters()))if(value&&!(ignoreCompany&&key==="company"))params.set(key,value);return params.toString()?`?${params}`:""}
function filterIssues(){const f=activeFilters(),q=f.q.toLowerCase(),isAdmin=state.currentUser?.role==="Administrador";const rows=state.issues.filter(i=>(!q||JSON.stringify(i).toLowerCase().includes(q))&&(!f.status||i.status===f.status)&&(!f.specialty||i.type===f.specialty)&&(!f.company||i.company===f.company)&&(!f.asset||i.asset===f.asset)&&(!f.classification||i.classification===f.classification)&&(!f.fico_owner||i.owner===f.fico_owner)&&(!f.opened_from||i.openedAt>=f.opened_from)&&(!f.opened_to||i.openedAt<=f.opened_to));state.visibleIssueIds=rows.map(issue=>issue.id);$("#issuesTable").innerHTML=rows.map(i=>`<tr class="clickable" data-issue="${i.id}"><td class="admin-only ${isAdmin?"":"hidden"}"><input type="checkbox" data-select-issue="${i.id}" ${state.selectedIssues.has(i.id)?"checked":""} aria-label="Selecionar pendência ${i.id}"></td><td><strong>#${i.id}</strong><small>${i.classification}</small></td><td><strong>${i.type}</strong><small>${i.description.slice(0,58)}${i.description.length>58?"…":""}</small></td><td><strong>${i.asset}</strong><small>${i.km}</small></td><td>${i.company}</td><td>${formatDate(i.deadline)}</td><td><span class="status ${statusClass(i.status)}">${i.status}</span></td><td><button class="row-action">Abrir</button></td></tr>`).join("");bindIssueLinks();$$('[data-select-issue]').forEach(checkbox=>checkbox.onchange=event=>{event.stopPropagation();const id=+checkbox.dataset.selectIssue;if(checkbox.checked)state.selectedIssues.add(id);else state.selectedIssues.delete(id);updateBulkActions()});updateBulkActions()}
function updateBulkActions(){if(!$("#bulkActions"))return;const count=state.selectedIssues.size,isAdmin=state.currentUser?.role==="Administrador";$("#bulkActions").classList.toggle("hidden",!isAdmin||!count);$("#bulkSelectionCount").textContent=`${count} selecionada${count===1?"":"s"}`;if($("#selectVisibleIssues")){const visible=state.visibleIssueIds||[],selected=visible.filter(id=>state.selectedIssues.has(id)).length;$("#selectVisibleIssues").checked=!!visible.length&&selected===visible.length;$("#selectVisibleIssues").indeterminate=selected>0&&selected<visible.length}}
[$("#issueSearch"),$("#statusFilter"),$("#typeFilter"),$("#companyFilter"),$("#assetFilter"),$("#classificationFilter"),$("#ownerFilter"),$("#openedFromFilter"),$("#openedToFilter")].forEach(el=>el.addEventListener(el.tagName==="INPUT"?"input":"change",filterIssues));
$("#clearFiltersBtn").addEventListener("click",()=>{$("#issueSearch").value="";["#statusFilter","#typeFilter","#companyFilter","#assetFilter","#classificationFilter","#ownerFilter","#openedFromFilter","#openedToFilter"].forEach(selector=>$(selector).value="");filterIssues()});
$("#selectVisibleIssues").addEventListener("change",event=>{for(const id of state.visibleIssueIds||[]){if(event.target.checked)state.selectedIssues.add(id);else state.selectedIssues.delete(id)}filterIssues()});
$("#clearBulkSelectionBtn").addEventListener("click",()=>{state.selectedIssues.clear();filterIssues()});
$("#openBulkUpdateBtn").addEventListener("click",()=>{const form=$("#bulkUpdateForm");form.reset();$("#bulkUpdateSummary").innerHTML=`<strong>${state.selectedIssues.size} pendências selecionadas</strong><br>O histórico individual será preservado.`;updateBulkValueField();$("#bulkUpdateDialog").showModal()});
function updateBulkValueField(){const form=$("#bulkUpdateForm"),field=form.elements.field.value,input=form.elements.value,config={fico_owner:["text","Informe o nome completo do responsável FICO."],contractor_owner:["text","Informe o nome ou equipe responsável da contratada."],deadline_at:["date","Escolha o novo prazo."],classification:["text","Use Tipo A, Tipo B ou Tipo C."],company:["text","Use EMPA, ATERPA, APIA, GSA ou VALE."]}[field];input.type=config[0];input.value="";$("#bulkValueHelp").textContent=config[1]}
$("#bulkUpdateForm").elements.field.addEventListener("change",updateBulkValueField);$$('.close-bulk-dialog').forEach(button=>button.onclick=()=>$("#bulkUpdateDialog").close());
$("#bulkUpdateForm").addEventListener("submit",async event=>{event.preventDefault();if(!navigator.onLine){toast("A alteração em lote exige conexão.");return}const form=new FormData(event.target),button=event.submitter,original=button.textContent;button.disabled=true;button.textContent="Aplicando...";try{const response=await api("/issues/bulk-update",{method:"POST",body:JSON.stringify({issue_ids:[...state.selectedIssues],field:form.get("field"),value:form.get("value")})});state.selectedIssues.clear();$("#bulkUpdateDialog").close();await hydrateFromApi();renderAll();toast(`${response.updated} pendência${response.updated===1?"":"s"} atualizada${response.updated===1?"":"s"}. Backup automático criado.`)}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent=original}});
