function renderApprovals(){const eligible=state.issues.filter(i=>i.status==="Aguardando validação"&&(state.currentUser.role==="Administrador"||canApprove(i)));$("#approvalNotice").innerHTML=state.currentUser.globalApproval?"Você possui <strong>aprovação geral</strong>. Abra cada pendência e revise os dados e as duas evidências antes de decidir.":`Sua alçada atual: <strong>${state.currentUser.specialties.join(", ")||"sem especialidades de aprovação"}</strong>.`;$("#approvalCards").innerHTML=eligible.length?eligible.map(i=>`<article class="approval-review-card"><header class="approval-review-head"><div><span class="approval-id">#${i.id}</span><span class="status validacao">Aguardando validação</span></div><span class="approval-classification">${i.classification}</span></header><div class="approval-review-images"><figure><figcaption>Antes · condição registrada</figcaption><img src="${i.before}" alt="Foto de abertura da pendência ${i.id}"></figure><figure><figcaption>Depois · correção informada</figcaption><img src="${i.after}" alt="Foto da correção da pendência ${i.id}"></figure></div><div class="approval-review-content"><div><p class="eyebrow">${i.company} · ${i.type}</p><h3>${i.asset} · ${i.km}</h3><p class="approval-description">${i.description}</p></div><dl class="approval-facts"><div><dt>Prazo</dt><dd>${formatDate(i.deadline)}</dd></div><div><dt>Fiscal FICO</dt><dd>${i.owner}</dd></div><div><dt>Contratada</dt><dd>${i.contractor}</dd></div><div><dt>Segmento</dt><dd>${i.segment||"Não informado"}</dd></div></dl></div><footer class="approval-review-footer"><span>A decisão fica disponível somente após abrir a análise completa.</span><button class="btn primary" type="button" data-review="${i.id}">Analisar pendência</button></footer></article>`).join(""):'<div class="panel"><h3>Fila concluída</h3><p class="muted">Não há pendências aguardando sua validação.</p></div>';$$('[data-review]').forEach(button=>button.onclick=()=>openIssue(+button.dataset.review))}
async function completeDecision(id,approved,comment="",acceptance=false){const i=state.issues.find(x=>x.id===id);if(!canApprove(i)&&state.currentUser.role!=="Administrador"){throw new Error("Seu perfil não possui alçada para esta pendência.")}if(API_ENABLED){const response=await api(`/issues/${id}/decision`,{method:"POST",body:JSON.stringify({decision:approved?"approve":"reject",comment,confirmed_review:approved,acceptance_term:approved&&acceptance,...issueVersion(i)})});if(response.queued){i.status=approved?"Baixada":"Rejeitada";i.history.push(`${approved?"Baixa assinada aguardando sincronização":"Rejeição aguardando sincronização"}: ${comment}`)}else await hydrateFromApi()}else{i.status=approved?"Baixada":"Rejeitada";i.history.push(`${approved?"Baixa aprovada e assinada":"Correção rejeitada"} por ${state.currentUser.name}${comment?`: ${comment}`:""}`);save()}renderAll();await updateSyncStatus();toast(navigator.onLine?(approved?`Pendência #${id} baixada e assinada com sucesso.`:`Pendência #${id} devolvida à contratada.`):"Operação salva no aparelho e aguardando conexão.")}
function openApprovalConfirmation(issue){const form=$("#approvalForm");form.reset();form.elements.issueId.value=issue.id;$("#approvalConfirmationSummary").innerHTML=`<div class="approval-final-head"><div><strong>Pendência #${issue.id} · ${issue.type}</strong><span>${issue.company} · ${issue.asset} · ${issue.km}</span></div><span class="status validacao">Aguardando validação</span></div><div class="approval-final-images"><figure><figcaption>Antes</figcaption><img src="${issue.before}" alt="Condição inicial da pendência ${issue.id}"></figure><figure><figcaption>Depois</figcaption><img src="${issue.after}" alt="Condição após a correção da pendência ${issue.id}"></figure></div><div class="approval-final-description"><small>Descrição da pendência</small><p>${issue.description}</p></div><dl class="approval-final-facts"><div><dt>Classificação</dt><dd>${issue.classification}</dd></div><div><dt>Prazo</dt><dd>${formatDate(issue.deadline)}</dd></div><div><dt>Fiscal</dt><dd>${issue.owner}</dd></div><div><dt>Contratada</dt><dd>${issue.contractor}</dd></div></dl>`;$("#approvalDialog").showModal()}
async function decide(id,approved){const issue=state.issues.find(item=>item.id===id);if(!approved){$("#decisionForm").elements.issueId.value=id;$("#decisionDialog").showModal();return}openApprovalConfirmation(issue)}

function openAdminPasswordReset(user){const form=$("#resetPasswordForm");form.reset();form.elements.userId.value=user.id;$("#resetPasswordSummary").innerHTML=`<strong>${user.name}</strong><br>${user.email} · ${user.company}`;$("#resetPasswordDialog").showModal()}
function renderUsers(){const requests=state.passwordResetRequests,panel=$("#passwordResetPanel");panel.classList.toggle("hidden",!requests.length);panel.innerHTML=requests.length?`<div><p class="eyebrow">Recuperação de acesso</p><h3>${requests.length} solicitação${requests.length===1?"":"ões"} aguardando atendimento</h3></div><div class="reset-request-list">${requests.map(request=>`<button type="button" data-request-reset="${request.user_id}"><span><strong>${request.name}</strong><small>${request.email} · ${request.company}</small></span><b>Redefinir senha</b></button>`).join("")}</div>`:"";$("#usersTable").innerHTML=state.users.map(u=>`<tr><td><div style="display:flex;gap:10px;align-items:center"><div class="avatar">${initials(u.name)}</div><div><strong>${u.name}</strong><small>${u.email}</small></div></div></td><td>${u.company}</td><td>${u.role}</td><td class="permission-list">${u.globalApproval?'<strong>Aprovação geral</strong>':(u.specialties||[]).join(", ")||"Sem permissão de baixa"}</td><td><span class="status ${u.active?"baixada":"rejeitada"}">${u.active?"Ativo":"Inativo"}</span></td><td><div class="user-actions">${u.id!==state.currentUser.id?`<button class="reset-user-password" data-reset-password="${u.id}">Redefinir senha</button>`:""}<button class="toggle-status" data-user="${u.id}">${u.active?"Desativar":"Ativar"}</button>${u.email.endsWith(".teste@atlas-fico.local")?`<button class="delete-user" data-delete-user="${u.id}">Excluir teste</button>`:""}</div></td></tr>`).join("");$$('[data-reset-password],[data-request-reset]').forEach(button=>button.onclick=()=>openAdminPasswordReset(state.users.find(user=>user.id===+(button.dataset.resetPassword||button.dataset.requestReset))));$$('[data-user]').forEach(b=>b.onclick=async()=>{const u=state.users.find(x=>x.id===+b.dataset.user);if(u.id===state.currentUser.id){toast("Não é possível desativar o próprio usuário.");return}try{if(API_ENABLED)await api(`/users/${u.id}/status`,{method:"PATCH",body:JSON.stringify({active:!u.active})});u.active=!u.active;if(!API_ENABLED)save();renderUsers();toast(`Usuário ${u.active?"ativado":"desativado"}.`)}catch(error){toast(error.message)}});$$('[data-delete-user]').forEach(b=>b.onclick=async()=>{const u=state.users.find(x=>x.id===+b.dataset.deleteUser);if(!confirm(`Excluir definitivamente o perfil ${u.name}?`))return;try{await api(`/users/${u.id}`,{method:"DELETE"});state.users=state.users.filter(x=>x.id!==u.id);renderUsers();toast("Perfil de teste excluído.")}catch(error){toast(error.message)}})}

function bindIssueLinks(){$$('[data-issue]').forEach(el=>el.onclick=e=>{if(e.target.closest("[data-approve],[data-reject],[data-select-issue]"))return;const issue=state.issues.find(i=>i.id===+el.dataset.issue);openIssue(issue.id);if(state.currentUser.role==="Administrador")addAdminEditAction(issue)})}
function addAdminEditAction(issue){const actions=document.createElement("div");actions.className="drawer-actions admin-edit-actions";actions.innerHTML='<button class="btn ghost" type="button">Editar dados, responsáveis e fotos</button>';actions.querySelector("button").onclick=()=>openEditIssue(issue);$("#issueDrawerContent").append(actions)}
function openEditIssue(issue){closeDrawer();const form=$("#editIssueForm");form.elements.issueId.value=issue.id;form.elements.company.value=issue.company;form.elements.classification.value=issue.classification;form.elements.specialty.value=issue.type;form.elements.asset.value=issue.asset;form.elements.ficoOwner.value=issue.owner==="Não atribuído"?"":issue.owner;form.elements.contractorOwner.value=issue.contractor==="Não atribuído"?"":issue.contractor;form.elements.deadlineAt.value=issue.deadline||"";form.elements.kmStart.value=issue.kmStart||"";form.elements.kmEnd.value=issue.kmEnd||"";form.elements.description.value=issue.description;$("#editIssueDialog").showModal()}
function openIssue(id){const i=state.issues.find(x=>x.id===id);const auth=canApprove(i)||state.currentUser.role==="Administrador";const submit=canSubmitCorrection(i);const evidence=i.after?`<section class="evidence-section"><div class="section-label"><span>Comparação fotográfica</span><small>Confira enquadramento, local e serviço executado</small></div><div class="drawer-evidence-grid"><figure><figcaption>Antes</figcaption><img src="${i.before}" alt="Condição inicial da pendência ${i.id}"></figure><figure><figcaption>Depois</figcaption><img src="${i.after}" alt="Condição após correção da pendência ${i.id}"></figure></div></section>`:`<section class="evidence-section"><div class="section-label"><span>Evidência de abertura</span></div><figure class="drawer-single-evidence"><img src="${i.before}" alt="Condição inicial da pendência ${i.id}"></figure></section>`;$("#issueDrawerContent").innerHTML=`<div class="drawer-head"><div><p class="eyebrow">Pendência #${i.id}</p><h2>${i.type}</h2><span class="status ${statusClass(i.status)}">${i.status}</span></div><button class="icon-btn" id="closeDrawer">×</button></div><div class="drawer-body">${flowStepper(i.status)}${evidence}<div class="detail-grid"><div class="detail-item"><small>Empresa</small><strong>${i.company}</strong></div><div class="detail-item"><small>Classificação</small><strong>${i.classification}</strong></div><div class="detail-item"><small>Ativo e segmento</small><strong>${i.asset} · ${i.segment||"Não informado"}</strong></div><div class="detail-item"><small>Localização</small><strong>${i.km}</strong></div><div class="detail-item"><small>Prazo</small><strong>${formatDate(i.deadline)}</strong></div><div class="detail-item"><small>Fiscal responsável</small><strong>${i.owner}</strong></div><div class="detail-item"><small>Responsável contratada</small><strong>${i.contractor}</strong></div><div class="detail-item"><small>Data de abertura</small><strong>${formatDate(i.openedAt)}</strong></div></div><section class="drawer-description"><h3>Descrição completa</h3><p>${i.description}</p></section><h3>Histórico</h3><div class="timeline">${i.history.map((h,k)=>`<div class="timeline-item"><h4>${h}</h4><p>${k?"Hoje":"10/07/2026"} · Registro auditado</p></div>`).join("")}</div>${i.status==="Baixada"?`<button class="btn ghost certificate-btn" id="downloadCertificate">Baixar comprovante de encerramento</button>`:""}</div>${submit?`<div class="drawer-actions"><button class="btn primary" id="drawerCorrection">Informar correção e enviar foto</button></div>`:""}${i.status==="Aguardando validação"&&auth?`<div class="drawer-actions review-actions"><button class="btn danger" id="drawerReject">Rejeitar correção</button><button class="btn primary" id="drawerApprove">Revisar e confirmar baixa</button></div>`:""}`;$("#drawerOverlay").classList.remove("hidden");$("#issueDrawer").classList.remove("hidden");$("#closeDrawer").onclick=closeDrawer;if($("#downloadCertificate"))$("#downloadCertificate").onclick=async()=>{try{await downloadApi(`/issues/${i.id}/certificate.pdf`)}catch(error){toast(error.message)}};if($("#drawerCorrection"))$("#drawerCorrection").onclick=()=>openCorrection(i);if($("#drawerApprove"))$("#drawerApprove").onclick=()=>decide(id,true);if($("#drawerReject"))$("#drawerReject").onclick=()=>decide(id,false)}
function closeDrawer(){$("#drawerOverlay").classList.add("hidden");$("#issueDrawer").classList.add("hidden")}$("#drawerOverlay").onclick=closeDrawer;
const openIssueBase=openIssue;
openIssue=function(id){openIssueBase(id);const issue=state.issues.find(item=>item.id===id);appendIssueCollaboration(issue)};
function appendIssueCollaboration(issue){const body=$("#issueDrawerContent .drawer-body");if(!body||!issue)return;const signature=issue.signature?`<section class="signature-card"><small>ENCERRAMENTO ASSINADO ELETRONICAMENTE</small><strong>${escapeHtml(issue.signature.signer_name)}</strong><span>${escapeHtml(issue.signature.signer_email)} · ${formatMoment(issue.signature.signed_at)}</span><p>${escapeHtml(issue.signature.acceptance_text)}</p></section>`:"",comments=(issue.comments||[]).map(comment=>`<article class="issue-comment"><div><strong>${escapeHtml(comment.author)}</strong><time>${formatMoment(comment.created_at)}</time></div><p>${escapeHtml(comment.body)}</p>${comment.attachment?`<a href="${comment.attachment}" target="_blank" rel="noopener"><img src="${comment.attachment}" alt="Anexo do comentário"></a>`:""}</article>`).join("");body.insertAdjacentHTML("beforeend",`${signature}<section class="comments-section"><div class="section-label"><span>Comentários e comunicação</span><small>${(issue.comments||[]).length} registro${(issue.comments||[]).length===1?"":"s"}</small></div><div class="comments-list">${comments||'<p class="muted">Nenhum comentário registrado.</p>'}</div><form id="issueCommentForm" class="comment-form"><textarea name="body" rows="3" required placeholder="Registre uma orientação, informação de campo ou alinhamento"></textarea><label class="comment-attachment">Anexar foto opcional<input name="photo" type="file" accept="image/*" capture="environment"></label><button class="btn primary" type="submit">Adicionar comentário</button></form></section>`);$("#issueCommentForm").onsubmit=async event=>{event.preventDefault();const form=new FormData(event.target),file=event.target.elements.photo.files[0],payload={body:form.get("body"),captured_at:new Date().toISOString(),...issueVersion(issue)};if(file){payload.photo_name=file.name;payload.photo_data_url=await fileToDataUrl(file)}const button=event.submitter,original=button.textContent;button.disabled=true;button.textContent="Salvando...";try{const response=await api(`/issues/${issue.id}/comments`,{method:"POST",body:JSON.stringify(payload)});if(response.queued){issue.comments.push({id:`local-${Date.now()}`,body:payload.body,author:state.currentUser.name,created_at:new Date().toISOString(),attachment:payload.photo_data_url||null})}else await hydrateFromApi();renderAll();openIssue(issue.id);toast(navigator.onLine?"Comentário registrado.":"Comentário salvo no aparelho e aguardando conexão.")}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent=original}}}
