const escapeHtml=value=>String(value??"").replace(/[&<>'"]/g,character=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"})[character]);
const formatMoment=value=>value?new Intl.DateTimeFormat("pt-BR",{dateStyle:"short",timeStyle:"short"}).format(new Date(value)):"Ainda não sincronizado";
function syncOperationInfo(item){if(item.path==="/issues")return {title:"Nova pendência",issue:`Registro temporário ${-item.id}`,detail:`${item.body.company} · ${item.body.asset}`};const match=item.path.match(/^\/issues\/(-?\d+)\/(correction|decision|comments)$/);if(!match)return {title:"Operação",issue:item.path,detail:""};if(match[2]==="correction")return {title:"Foto de correção",issue:`Pendência #${match[1]}`,detail:item.body.comment||"Correção registrada em campo"};if(match[2]==="comments")return {title:"Comentário",issue:`Pendência #${match[1]}`,detail:item.body.body||"Comunicação registrada em campo"};return {title:item.body.decision==="approve"?"Aprovação de baixa assinada":"Rejeição da correção",issue:`Pendência #${match[1]}`,detail:item.body.comment||"Decisão registrada em campo"}}
async function renderSyncCenter(){if(!window.AtlasOffline||!$("#syncQueue"))return;const items=await AtlasOffline.pending(),info=await AtlasOffline.stats();$("#syncOverview").innerHTML=`<div><small>Na fila</small><strong>${info.pending}</strong><span>operações neste aparelho</span></div><div><small>Conflitos</small><strong>${info.conflicts}</strong><span>exigem decisão</span></div><div><small>Falhas de envio</small><strong>${info.errors}</strong><span>podem ser tentadas novamente</span></div><div><small>Último envio</small><strong class="sync-date">${formatMoment(info.lastSuccessAt)}</strong><span>${navigator.onLine?"conectado à internet":"trabalhando offline"}</span></div>`;$("#syncAllBtn").disabled=!navigator.onLine||!items.length;$("#syncQueue").innerHTML=items.length?items.map(item=>{const operation=syncOperationInfo(item),stateClass=item.conflict?"conflict":item.lastError?"error":"pending",stateLabel=item.conflict?"Conflito de versão":item.lastError?"Falha no envio":"Aguardando envio",preview=item.body.photo_data_url?`<img class="sync-photo" src="${item.body.photo_data_url}" alt="Foto aguardando sincronização">`:"";return `<article class="sync-card ${stateClass}" data-sync-item="${item.id}"><div class="sync-card-main">${preview}<div><div class="sync-card-title"><span class="sync-state">${stateLabel}</span><small>${formatMoment(item.createdAt)}</small></div><h3>${operation.title}</h3><strong>${operation.issue}</strong><p>${escapeHtml(operation.detail)}</p>${item.lastError?`<div class="sync-error">${escapeHtml(item.lastError)}</div>`:""}${item.conflict?`<div class="conflict-compare"><div><small>Versão no aparelho</small><strong>${escapeHtml(item.body.base_updated_at?formatMoment(item.body.base_updated_at):"registro novo")}</strong></div><div><small>Versão no servidor</small><strong>${escapeHtml(item.server?.status||"alterada")}</strong><span>${escapeHtml(formatMoment(item.server?.updated_at))}</span></div></div>`:""}</div></div><div class="sync-card-actions">${item.conflict?`<button class="btn ghost" data-sync-discard="${item.id}">Usar versão do servidor</button><button class="btn primary" data-sync-force="${item.id}">Reaplicar minha alteração</button>`:`<button class="btn ghost" data-sync-discard="${item.id}">Descartar</button><button class="btn primary" data-sync-retry="${item.id}" ${navigator.onLine?"":"disabled"}>Enviar agora</button>`}</div></article>`}).join(""):`<div class="sync-empty"><span>✓</span><h3>Fila sincronizada</h3><p>Este aparelho não possui operações aguardando envio.</p></div>`;$$('[data-sync-retry]').forEach(button=>button.onclick=async()=>{await AtlasOffline.retry(+button.dataset.syncRetry);await syncNow(+button.dataset.syncRetry)});$$('[data-sync-force]').forEach(button=>button.onclick=async()=>{await AtlasOffline.retry(+button.dataset.syncForce,true);await syncNow(+button.dataset.syncForce)});$$('[data-sync-discard]').forEach(button=>button.onclick=async()=>{if(button.dataset.armed!=="true"){button.dataset.armed="true";button.textContent="Clique novamente para confirmar";setTimeout(()=>{button.dataset.armed="false";button.textContent=button.closest('.sync-card').classList.contains('conflict')?"Usar versão do servidor":"Descartar"},3500);return}await AtlasOffline.discard(+button.dataset.syncDiscard);await hydrateFromApi();renderAll();await updateSyncStatus();toast("Operação local descartada. A versão do servidor foi preservada.")})}

const kmNumber=value=>{const text=String(value||"").toUpperCase().replace(/^\s*KM\s*/,"").trim(),plus=text.match(/(\d+(?:[.,]\d+)?)\s*\+\s*(\d{1,3})/);if(plus)return Number(plus[1].replace(",","."))+Number(plus[2])/1000;const decimal=text.match(/\d+(?:[.,]\d+)?/);if(!decimal)return Number.POSITIVE_INFINITY;const number=Number(decimal[0].replace(",","."));return number>=1000?number/1000:number};
const kmLabel=value=>Number.isFinite(value)?value.toLocaleString("pt-BR",{minimumFractionDigits:0,maximumFractionDigits:3}):"—";
function filteredMapIssues(){return state.issues.filter(issue=>(!$("#mapCompanyFilter").value||issue.company===$("#mapCompanyFilter").value)&&(!$("#mapAssetFilter").value||issue.asset===$("#mapAssetFilter").value)&&(!$("#mapStatusFilter").value||issue.status===$("#mapStatusFilter").value)&&(!$("#mapTypeFilter").value||issue.type===$("#mapTypeFilter").value))}
function issueKmRange(issue){const first=kmNumber(issue.kmStart),last=kmNumber(issue.kmEnd),values=[first,last].filter(Number.isFinite);if(!values.length)return null;return {start:Math.min(...values),end:Math.max(...values)}}
function renderKmGroup(asset,issues){const ranges=issues.map(issue=>({issue,range:issueKmRange(issue)})).filter(item=>item.range),minimum=Math.min(...ranges.map(item=>item.range.start)),maximum=Math.max(...ranges.map(item=>item.range.end)),span=Math.max(maximum-minimum,.001),ticks=Array.from({length:5},(_,index)=>minimum+span*index/4);return `<section class="km-asset-group"><header><div><small>ATIVO</small><h3>${escapeHtml(asset||"Ativo não informado")}</h3></div><strong>KM ${kmLabel(minimum)} — ${kmLabel(maximum)}</strong></header><div class="km-axis">${ticks.map((tick,index)=>`<span style="left:${index*25}%">${kmLabel(tick)}</span>`).join("")}</div><div class="km-range-list">${ranges.slice(0,120).map(({issue,range})=>{const left=Math.max(0,Math.min(100,(range.start-minimum)/span*100)),rawWidth=(range.end-range.start)/span*100,width=Math.max(1.2,rawWidth),adjustedLeft=Math.min(left,100-width);return `<button type="button" class="km-range-row" data-map-open="${issue.id}"><span class="km-range-id">#${issue.id}</span><span class="km-range-track"><i class="${statusClass(issue.status)}" style="--range-left:${adjustedLeft}%;--range-width:${width}%"></i></span><span class="km-range-details"><strong>KM ${kmLabel(range.start)} → ${kmLabel(range.end)}</strong><small>${escapeHtml(issue.type)} · ${escapeHtml(issue.status)}</small></span></button>`}).join("")}${ranges.length>120?`<p class="linear-limit">Mostrando 120 de ${ranges.length} pendências deste ativo. Use os filtros para reduzir a seleção.</p>`:""}</div></section>`}
function renderMap(){if(!$("#issuesMap"))return;setFilterOptions("#mapCompanyFilter","Todas as empresas",[...new Set(state.issues.map(issue=>issue.company))]);setFilterOptions("#mapAssetFilter","Todos os ativos",[...new Set(state.issues.map(issue=>issue.asset))]);setFilterOptions("#mapStatusFilter","Todos os status",[...new Set(state.issues.map(issue=>issue.status))]);setFilterOptions("#mapTypeFilter","Todas as especialidades",[...new Set(state.issues.map(issue=>issue.type))]);const issues=filteredMapIssues(),withKm=issues.filter(issue=>issueKmRange(issue)),groups=new Map();withKm.forEach(issue=>{const asset=issue.asset||"Ativo não informado";if(!groups.has(asset))groups.set(asset,[]);groups.get(asset).push(issue)});$("#mapEmpty").classList.toggle("hidden",withKm.length>0);$("#issuesMap").innerHTML=[...groups.entries()].sort(([a],[b])=>a.localeCompare(b,"pt-BR")).map(([asset,items])=>renderKmGroup(asset,items.sort((a,b)=>issueKmRange(a).start-issueKmRange(b).start||a.id-b.id))).join("");const ordered=[...issues].sort((a,b)=>kmNumber(a.kmStart)-kmNumber(b.kmStart)||kmNumber(a.kmEnd)-kmNumber(b.kmEnd)||a.id-b.id);$("#linearMapCount").textContent=`${issues.length} registro${issues.length===1?"":"s"}`;$("#linearMap").innerHTML=ordered.slice(0,300).map(issue=>`<button type="button" class="linear-map-item" data-linear-issue="${issue.id}"><span class="linear-km">${escapeHtml(issue.kmStart||"—")} → ${escapeHtml(issue.kmEnd||issue.kmStart||"—")}</span><i class="linear-node ${statusClass(issue.status)}"></i><span><strong>#${issue.id} · ${escapeHtml(issue.asset)}</strong><small>${escapeHtml(issue.company)} · ${escapeHtml(issue.type)} · ${escapeHtml(issue.status)}</small></span></button>`).join("")+(ordered.length>300?`<p class="linear-limit">Mostrando os primeiros 300 registros. Use os filtros para reduzir a carteira.</p>`:"");$$('[data-map-open],[data-linear-issue]').forEach(button=>button.onclick=()=>openIssue(+(button.dataset.mapOpen||button.dataset.linearIssue)))}

function renderContractorPerformance(){const target=$("#contractorPerformanceTable");if(!target||state.currentUser?.role!=="Administrador")return;const today=new Date(),companies=[...new Set(state.issues.map(issue=>issue.company).filter(company=>company&&company!=="FICO"&&company!=="VALE"))],rows=companies.map(company=>{const issues=state.issues.filter(issue=>issue.company===company),closed=issues.filter(issue=>issue.status==="Baixada"),overdue=issues.filter(issue=>issue.status!=="Baixada"&&issue.deadline&&new Date(`${issue.deadline}T23:59:59`)<today),rejected=issues.filter(issue=>issue.historyEntries?.some(entry=>entry.event==="CORRECAO_REJEITADA")||issue.status==="Rejeitada"),corrected=issues.filter(issue=>issue.historyEntries?.some(entry=>String(entry.event).includes("CORRECAO_"))),keys=new Map();issues.forEach(issue=>{const key=[issue.asset,issue.type,issue.kmStart,issue.kmEnd].join("|");keys.set(key,(keys.get(key)||0)+1)});const recurrent=issues.filter(issue=>keys.get([issue.asset,issue.type,issue.kmStart,issue.kmEnd].join("|"))>1).length,days=closed.map(issue=>issue.openedAt&&issue.closedAt?Math.max(0,(new Date(`${issue.closedAt}T12:00:00`)-new Date(`${issue.openedAt}T12:00:00`))/86400000):null).filter(Number.isFinite),average=days.length?Math.round(days.reduce((sum,value)=>sum+value,0)/days.length):null;return {company,total:issues.length,closed:closed.length,rate:issues.length?Math.round(closed.length/issues.length*100):0,overdue:overdue.length,rejection:corrected.length?Math.round(rejected.length/corrected.length*100):0,recurrent,average}}).sort((a,b)=>b.total-a.total);target.innerHTML=`<table class="performance-table"><thead><tr><th>Empresa</th><th>Carteira</th><th>Baixadas</th><th>Taxa</th><th>Atrasadas</th><th>Rejeição</th><th>Reincidências</th><th>Prazo médio</th></tr></thead><tbody>${rows.map(row=>`<tr><td><strong>${escapeHtml(row.company)}</strong></td><td>${row.total}</td><td>${row.closed}</td><td><strong>${row.rate}%</strong></td><td>${row.overdue}</td><td>${row.rejection}%</td><td>${row.recurrent}</td><td>${row.average==null?"—":`${row.average} dias`}</td></tr>`).join("")}</tbody></table>`}

function qualityReasons(issue){const reasons=[];if(!issue.kmStart)reasons.push("KM inicial ausente");if(!issue.kmEnd)reasons.push("KM final ausente");if(!issue.deadline)reasons.push("Prazo ausente");if(!issue.owner||issue.owner==="Não atribuído")reasons.push("Responsável FICO ausente");if(!issue.contractor||issue.contractor==="Não atribuído")reasons.push("Responsável contratada ausente");if(!issue.hasOpeningPhoto)reasons.push("Foto de abertura ausente");if(!issue.asset)reasons.push("Ativo ausente");if(!issue.classification)reasons.push("Classificação ausente");return reasons}
function renderQuality(){if(!$("#qualityMetrics")||state.currentUser?.role!=="Administrador")return;const categories=[{label:"Sem KM completo",test:issue=>!issue.kmStart||!issue.kmEnd},{label:"Sem prazo",test:issue=>!issue.deadline},{label:"Sem responsável",test:issue=>!issue.owner||issue.owner==="Não atribuído"||!issue.contractor||issue.contractor==="Não atribuído"},{label:"Sem foto de abertura",test:issue=>!issue.hasOpeningPhoto}],incomplete=state.issues.map(issue=>({issue,reasons:qualityReasons(issue)})).filter(item=>item.reasons.length);$("#qualityMetrics").innerHTML=categories.map(category=>`<article><small>${category.label}</small><strong>${state.issues.filter(category.test).length}</strong><span>pendências</span></article>`).join("");$("#qualityIssueCount").textContent=`${incomplete.length} registro${incomplete.length===1?"":"s"}`;$("#qualityIssueList").innerHTML=incomplete.slice(0,300).map(({issue,reasons})=>`<button type="button" data-quality-issue="${issue.id}"><span><strong>#${issue.id} · ${escapeHtml(issue.asset||"Ativo não informado")}</strong><small>${escapeHtml(issue.company)} · ${escapeHtml(issue.type)}</small></span><span class="quality-tags">${reasons.map(reason=>`<i>${escapeHtml(reason)}</i>`).join("")}</span></button>`).join("")||'<div class="sync-empty"><span>✓</span><h3>Carteira consistente</h3><p>Nenhuma pendência apresenta os problemas monitorados.</p></div>';$$('[data-quality-issue]').forEach(button=>button.onclick=()=>{const issue=state.issues.find(item=>item.id===+button.dataset.qualityIssue);openIssue(issue.id);addAdminEditAction(issue)})}

async function loadNotifications(){if(!state.currentUser||!$("#notificationList"))return;const data=await api("/notifications");state.notifications=data.items||[];state.notificationUnread=data.unread||0;renderNotifications()}
function renderNotifications(){const dot=$("#notificationDot");dot.classList.toggle("hidden",!state.notificationUnread);$("#notificationSummary").textContent=state.notificationUnread?`${state.notificationUnread} não lida${state.notificationUnread===1?"":"s"}`:"Tudo em dia";$("#notificationList").innerHTML=state.notifications.length?state.notifications.map(item=>`<button type="button" class="notification-item ${item.read_at?"":"unread"}" data-notification="${item.id}" data-notification-issue="${item.issue_id||""}"><i>${item.kind.slice(0,1)}</i><span><strong>${escapeHtml(item.title)}</strong><small>${escapeHtml(item.message)}</small><time>${formatMoment(item.created_at)}</time></span></button>`).join(""):'<div class="sync-empty"><span>✓</span><h3>Sem notificações</h3><p>Novas atribuições, prazos e decisões aparecerão aqui.</p></div>';$$('[data-notification]').forEach(button=>button.onclick=async()=>{const id=+button.dataset.notification,issueId=+button.dataset.notificationIssue;if(!button.classList.contains("unread")||!navigator.onLine){if(issueId)openIssue(issueId);return}await api(`/notifications/${id}/read`,{method:"POST",body:"{}"});const item=state.notifications.find(notification=>notification.id===id);if(item)item.read_at=new Date().toISOString();state.notificationUnread=Math.max(0,state.notificationUnread-1);renderNotifications();if(issueId)openIssue(issueId)})}

async function loadBackups(){if(state.currentUser?.role!=="Administrador"||!$("#backupList"))return;try{state.backups=await api("/admin/backups");renderBackups()}catch(error){$("#backupList").innerHTML=`<div class="sync-empty"><h3>Backups indisponíveis</h3><p>${escapeHtml(error.message)}</p></div>`}}
function renderBackups(){$("#backupList").innerHTML=state.backups.length?state.backups.map(backup=>`<article class="backup-card"><div class="backup-icon">▣</div><div><small>Ponto #${backup.id}</small><h3>${escapeHtml(backup.label)}</h3><p>${backup.issue_count} pendências · criado por ${escapeHtml(backup.created_by_name)} em ${formatMoment(backup.created_at)}</p></div><div class="backup-actions"><button class="btn ghost" data-backup-download="${backup.id}">Baixar JSON</button><button class="btn danger-soft" data-backup-restore="${backup.id}">Restaurar</button></div></article>`).join(""):`<div class="sync-empty"><span>▣</span><h3>Nenhum ponto criado</h3><p>Crie o primeiro backup antes de uma importação ou alteração administrativa importante.</p></div>`;$$('[data-backup-download]').forEach(button=>button.onclick=async()=>{try{await downloadApi(`/admin/backups/${button.dataset.backupDownload}/download`)}catch(error){toast(error.message)}});$$('[data-backup-restore]').forEach(button=>button.onclick=async()=>{const info=await AtlasOffline.stats();if(info.pending){toast("Sincronize ou descarte a fila deste aparelho antes de restaurar um backup.");showView("sync");return}const backup=state.backups.find(item=>item.id===+button.dataset.backupRestore),form=$("#restoreBackupForm");form.reset();form.elements.backupId.value=backup.id;$("#restoreBackupSummary").innerHTML=`<strong>${escapeHtml(backup.label)}</strong><span>${backup.issue_count} pendências · ${formatMoment(backup.created_at)}</span>`;$("#restoreBackupDialog").showModal()})}

$("#executiveCompanyFilter").addEventListener("change",renderExecutiveDashboard);
$("#exportDashboardBtn").addEventListener("click",async()=>{try{await downloadApi(`/exports/dashboard.pdf${reportQuery()}`)}catch(error){toast(error.message)}});
$("#exportCompanyDashboardsBtn").addEventListener("click",async()=>{try{await downloadApi(`/exports/company-dashboards.zip${reportQuery(true)}`)}catch(error){toast(error.message)}});
$("#exportExcelBtn").addEventListener("click",async()=>{try{await downloadApi(`/exports/issues.xlsx${reportQuery()}`)}catch(error){toast(error.message)}});
$("#exportPdfBtn").addEventListener("click",async()=>{try{await downloadApi(`/exports/issues.pdf${reportQuery()}`)}catch(error){toast(error.message)}});
$("#prepareOfflineBtn").addEventListener("click",prepareOffline);
$("#prepareOfflineMobileBtn").addEventListener("click",prepareOffline);
[$("#mapCompanyFilter"),$("#mapAssetFilter"),$("#mapStatusFilter"),$("#mapTypeFilter")].forEach(filter=>filter.addEventListener("change",renderMap));
$("#syncAllBtn").addEventListener("click",()=>syncNow());
$("#notificationBtn").addEventListener("click",async()=>{$("#notificationPanel").classList.toggle("hidden");if(!$("#notificationPanel").classList.contains("hidden"))await loadNotifications().catch(error=>toast(error.message))});
$("#closeNotifications").addEventListener("click",()=>$("#notificationPanel").classList.add("hidden"));
$("#readAllNotifications").addEventListener("click",async()=>{if(!navigator.onLine){toast("Conecte-se para atualizar as notificações.");return}await api("/notifications/read-all",{method:"POST",body:"{}"});state.notifications.forEach(item=>item.read_at=item.read_at||new Date().toISOString());state.notificationUnread=0;renderNotifications()});
$("#createBackupBtn").addEventListener("click",async()=>{if(!navigator.onLine){toast("Conecte-se à internet para criar um ponto de recuperação.");return}const button=$("#createBackupBtn"),original=button.textContent;button.disabled=true;button.textContent="Criando backup...";try{const response=await api("/admin/backups",{method:"POST",body:JSON.stringify({})});toast(`Ponto de recuperação criado com ${response.issue_count} pendências.`);await loadBackups()}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent=original}});
$$('.close-restore-dialog').forEach(button=>button.addEventListener("click",()=>$("#restoreBackupDialog").close()));
$("#restoreBackupForm").addEventListener("submit",async event=>{event.preventDefault();const form=new FormData(event.target),button=event.submitter;button.disabled=true;button.textContent="Restaurando...";try{const response=await api(`/admin/backups/${form.get("backupId")}/restore`,{method:"POST",body:JSON.stringify({confirmation:form.get("confirmation")})});$("#restoreBackupDialog").close();await hydrateFromApi();renderAll();showView("dashboard");toast(`Carteira restaurada: ${response.issue_count} pendências.`)}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent="Restaurar carteira"}});
function renderAll(){renderDashboard();renderContractorPerformance();renderIssues();renderApprovals();renderUsers();renderQuality();renderNotifications()}
if(window.AtlasOffline){AtlasOffline.register();addEventListener("online",()=>syncNow());addEventListener("offline",()=>{updateSyncStatus();renderSyncCenter()});addEventListener("atlas-sync-change",()=>{updateSyncStatus();renderSyncCenter()});addEventListener("atlas-sync-complete",()=>{updateSyncStatus();renderSyncCenter()})}
loadBuildInfo();
restoreSession();
if(window.AtlasOffline){$("#syncStatus").addEventListener("click",()=>showView("sync"));document.addEventListener("visibilitychange",()=>{if(!document.hidden&&navigator.onLine)syncNow()});setInterval(()=>{if(navigator.onLine)syncNow()},30000)}

let installPrompt;
const installButton=$("#installAppBtn");
const isIos=/iphone|ipad|ipod/i.test(navigator.userAgent);
const isStandalone=matchMedia("(display-mode: standalone)").matches||navigator.standalone===true;
addEventListener("beforeinstallprompt",event=>{event.preventDefault();installPrompt=event;installButton.classList.remove("hidden")});
if(isIos&&!isStandalone)installButton.classList.remove("hidden");
installButton.addEventListener("click",async()=>{
 if(installPrompt){installPrompt.prompt();await installPrompt.userChoice;installPrompt=null;installButton.classList.add("hidden");return}
 if(isIos){toast("No Safari, toque em Compartilhar e depois em Adicionar à Tela de Início.");return}
 toast("Abra o menu do navegador e selecione Instalar aplicativo.");
});
addEventListener("appinstalled",()=>{installButton.classList.add("hidden");toast("ATLAS instalado com sucesso.")});
